package com.company.snackledger.server.web;import org.springframework.context.annotation.*;import org.springframework.security.config.annotation.web.builders.HttpSecurity;import org.springframework.security.web.SecurityFilterChain;@Configuration public class SecurityConfig{@Bean SecurityFilterChain filter(HttpSecurity h)throws Exception{return h.csrf(c->c.disable()).authorizeHttpRequests(a->a.requestMatchers("/api/v1/kiosk/**","/dashboard/tv").permitAll().anyRequest().authenticated()).formLogin(f->f.permitAll()).build();}}
